local Players=game:GetService("Players")local UserInputService=game:GetService("UserInputService")local RunService=game:GetService("RunService")local LocalPlayer=Players.LocalPlayer local TweenService=game:GetService("TweenService")local Camera=workspace.CurrentCamera local Lighting=game:GetService("Lighting")repeat task.wait()until LocalPlayer and LocalPlayer.PlayerGui local Settings={ESP=true,Box=true,Tracer=true,Nome=true,Vida=true,Speed=false,SpeedVal=16,Multi=3,Aimbot=false,AimFOV=200,AimSmooth=5,Noclip=false,Fullbright=false}local Theme={Accent=Color3.fromRGB(0,180,255),Text=Color3.fromRGB(255,255,255),Green=Color3.fromRGB(55,255,55),Red=Color3.fromRGB(255,55,55)}local gui=Instance.new("ScreenGui")gui.Name="A"gui.ResetOnSpawn=false gui.ZIndexBehavior=Enum.ZIndexBehavior.Sibling gui.DisplayOrder=999 gui.Parent=LocalPlayer.PlayerGui local NotifFrame=Instance.new("Frame")NotifFrame.Size=UDim2.new(1,0,0,60)NotifFrame.Position=UDim2.new(0,0,0.5,-30)NotifFrame.BackgroundTransparency=1 NotifFrame.ZIndex=20 NotifFrame.Parent=gui local NotifText=Instance.new("TextLabel")NotifText.Size=UDim2.new(0,300,0,50)NotifText.Position=UDim2.new(0.5,-150,0.5,-25)NotifText.BackgroundColor3=Color3.fromRGB(15,15,20)NotifText.BackgroundTransparency=0.2 NotifText.TextColor3=Color3.fromRGB(255,255,255)NotifText.Font=Enum.Font.SourceSansBold NotifText.TextSize=12 NotifText.Text="Vc tá usando um script brasileiro\nEntão não espere muita coisa ;-;"NotifText.TextXAlignment=Enum.TextXAlignment.Center NotifText.TextYAlignment=Enum.TextYAlignment.Center NotifText.TextTransparency=0 NotifText.Parent=NotifFrame Instance.new("UICorner",NotifText).CornerRadius=UDim.new(0,12)local ns=Instance.new("UIStroke",NotifText)ns.Thickness=1 ns.Color=Color3.fromRGB(0,180,255)ns.Transparency=0.5 coroutine.wrap(function()task.wait(0.5)TweenService:Create(NotifText,TweenInfo.new(1,Enum.EasingStyle.Quad,Enum.EasingDirection.Out),{TextTransparency=1}):Play()task.wait(1.2)NotifFrame:Destroy()end)()local ESPGui=Instance.new("Frame")ESPGui.Size=UDim2.new(1,0,1,0)ESPGui.BackgroundTransparency=1 ESPGui.Parent=gui local FloatButton=Instance.new("TextButton")FloatButton.Size=UDim2.new(0,50,0,50)FloatButton.Position=UDim2.new(0,20,0.5,-25)FloatButton.BackgroundColor3=Theme.Accent FloatButton.BorderSizePixel=0 FloatButton.Text="⚡"FloatButton.TextSize=26 FloatButton.TextColor3=Color3.new(1,1,1)FloatButton.AutoButtonColor=false FloatButton.ZIndex=10 FloatButton.Parent=gui Instance.new("UICorner",FloatButton).CornerRadius=UDim.new(1,0)local MainPanel=Instance.new("Frame")MainPanel.Size=UDim2.new(0,280,0,350)MainPanel.Position=UDim2.new(0.5,-140,0.5,-175)MainPanel.BackgroundColor3=Color3.fromRGB(15,15,20)MainPanel.BorderSizePixel=0 MainPanel.Visible=false MainPanel.ZIndex=5 MainPanel.Parent=gui Instance.new("UICorner",MainPanel).CornerRadius=UDim.new(0,10)local TitleBar=Instance.new("Frame")TitleBar.Size=UDim2.new(1,0,0,38)TitleBar.BackgroundColor3=Color3.fromRGB(25,25,32)TitleBar.BorderSizePixel=0 TitleBar.Parent=MainPanel Instance.new("UICorner",TitleBar).CornerRadius=UDim.new(0,10)local tcover=Instance.new("Frame")tcover.Size=UDim2.new(1,0,0.5,0)tcover.Position=UDim2.new(0,0,0.5,0)tcover.BackgroundColor3=Color3.fromRGB(25,25,32)tcover.BorderSizePixel=0 tcover.Parent=TitleBar local TitleText=Instance.new("TextLabel")TitleText.Size=UDim2.new(1,-45,1,0)TitleText.Position=UDim2.new(0,12,0,0)TitleText.BackgroundTransparency=1 TitleText.TextColor3=Theme.Accent TitleText.Font=Enum.Font.SourceSansBold TitleText.TextSize=14 TitleText.Text="ARTHUR'S UNIVERSAL"TitleText.TextXAlignment=Enum.TextXAlignment.Left TitleText.Parent=TitleBar local CloseButton=Instance.new("TextButton")CloseButton.Size=UDim2.new(0,28,0,28)CloseButton.Position=UDim2.new(1,-33,0,5)CloseButton.BackgroundColor3=Theme.Red CloseButton.BorderSizePixel=0 CloseButton.Text="✕"CloseButton.TextSize=16 CloseButton.TextColor3=Color3.new(1,1,1)CloseButton.Font=Enum.Font.SourceSansBold CloseButton.AutoButtonColor=false CloseButton.Parent=TitleBar Instance.new("UICorner",CloseButton).CornerRadius=UDim.new(1,0)local TabContainer=Instance.new("Frame")TabContainer.Size=UDim2.new(1,0,0,32)TabContainer.Position=UDim2.new(0,0,0,38)TabContainer.BackgroundColor3=Color3.fromRGB(25,25,32)TabContainer.BorderSizePixel=0 TabContainer.Parent=MainPanel local function CreateTabButton(name,key,pos,active)local btn=Instance.new("TextButton")btn.Size=UDim2.new(0.25,-2,1,-4)btn.Position=UDim2.new(pos,1,0,2)btn.BackgroundColor3=active and Theme.Accent or Color3.fromRGB(40,40,48)btn.BorderSizePixel=0 btn.Text=name btn.TextSize=10 btn.TextColor3=Theme.Text btn.Font=Enum.Font.SourceSansBold btn.AutoButtonColor=false btn.Name=key btn.Parent=TabContainer Instance.new("UICorner",btn).CornerRadius=UDim.new(0,5)return btn end local TabAim=CreateTabButton("🎯 AIM","AIM",0,true)local TabVisual=CreateTabButton("👁️ VISUAL","VISUAL",0.25,false)local TabMove=CreateTabButton("🏃 MOVE","MOVE",0.5,false)local TabMisc=CreateTabButton("⚙️ MISC","MISC",0.75,false)local ContentArea=Instance.new("ScrollingFrame")ContentArea.Size=UDim2.new(1,-20,1,-80)ContentArea.Position=UDim2.new(0,10,0,75)ContentArea.BackgroundTransparency=1 ContentArea.BorderSizePixel=0 ContentArea.ScrollBarThickness=4 ContentArea.ScrollBarImageColor3=Theme.Accent ContentArea.CanvasSize=UDim2.new(0,0,0,300)ContentArea.Parent=MainPanel Instance.new("UIListLayout",ContentArea).Padding=UDim.new(0,4)local AimFrame=Instance.new("Frame")AimFrame.Name="AIM"AimFrame.Size=UDim2.new(1,0,0,200)AimFrame.BackgroundTransparency=1 AimFrame.Visible=true AimFrame.Parent=ContentArea Instance.new("UIListLayout",AimFrame).Padding=UDim.new(0,3)local VisualFrame=Instance.new("Frame")VisualFrame.Name="VISUAL"VisualFrame.Size=UDim2.new(1,0,0,200)VisualFrame.BackgroundTransparency=1 VisualFrame.Visible=false VisualFrame.Parent=ContentArea Instance.new("UIListLayout",VisualFrame).Padding=UDim.new(0,3)local MoveFrame=Instance.new("Frame")MoveFrame.Name="MOVE"MoveFrame.Size=UDim2.new(1,0,0,200)MoveFrame.BackgroundTransparency=1 MoveFrame.Visible=false MoveFrame.Parent=ContentArea Instance.new("UIListLayout",MoveFrame).Padding=UDim.new(0,3)local MiscFrame=Instance.new("Frame")MiscFrame.Name="MISC"MiscFrame.Size=UDim2.new(1,0,0,200)MiscFrame.BackgroundTransparency=1 MiscFrame.Visible=false MiscFrame.Parent=ContentArea Instance.new("UIListLayout",MiscFrame).Padding=UDim.new(0,3)local function CreateToggle(parent,name,default,callback)local c=Instance.new("Frame")c.Size=UDim2.new(1,0,0,35)c.BackgroundColor3=Color3.fromRGB(30,30,37)c.BorderSizePixel=0 c.Parent=parent Instance.new("UICorner",c).CornerRadius=UDim.new(0,5)local l=Instance.new("TextLabel")l.Size=UDim2.new(1,-55,1,0)l.Position=UDim2.new(0,8,0,0)l.BackgroundTransparency=1 l.TextColor3=Theme.Text l.Font=Enum.Font.SourceSans l.TextSize=13 l.Text=name l.TextXAlignment=Enum.TextXAlignment.Left l.Parent=c local tb=Instance.new("TextButton")tb.Size=UDim2.new(0,42,0,20)tb.Position=UDim2.new(1,-48,0.5,-10)tb.BackgroundColor3=default and Theme.Green or Color3.fromRGB(55,55,62)tb.BorderSizePixel=0 tb.Text=""tb.AutoButtonColor=false tb.Parent=c Instance.new("UICorner",tb).CornerRadius=UDim.new(1,0)local kn=Instance.new("Frame")kn.Size=UDim2.new(0,16,0,16)kn.Position=default and UDim2.new(1,-18,0.5,-8)or UDim2.new(0,2,0.5,-8)kn.BackgroundColor3=Color3.new(1,1,1)kn.BorderSizePixel=0 kn.Parent=tb Instance.new("UICorner",kn).CornerRadius=UDim.new(1,0)local en=default tb.Activated:Connect(function()en=not en local tp=en and UDim2.new(1,-18,0.5,-8)or UDim2.new(0,2,0.5,-8)TweenService:Create(kn,TweenInfo.new(0.15),{Position=tp}):Play()tb.BackgroundColor3=en and Theme.Green or Color3.fromRGB(55,55,62)callback(en)end)end local function CreateSlider(parent,name,min,max,default,callback)local c=Instance.new("Frame")c.Size=UDim2.new(1,0,0,50)c.BackgroundColor3=Color3.fromRGB(30,30,37)c.BorderSizePixel=0 c.Parent=parent Instance.new("UICorner",c).CornerRadius=UDim.new(0,5)local l=Instance.new("TextLabel")l.Size=UDim2.new(1,-16,0,18)l.Position=UDim2.new(0,8,0,4)l.BackgroundTransparency=1 l.TextColor3=Theme.Text l.Font=Enum.Font.SourceSans l.TextSize=13 l.Text=name..": "..default l.TextXAlignment=Enum.TextXAlignment.Left l.Parent=c local sb=Instance.new("Frame")sb.Size=UDim2.new(1,-16,0,6)sb.Position=UDim2.new(0,8,0,26)sb.BackgroundColor3=Color3.fromRGB(50,50,58)sb.BorderSizePixel=0 sb.Parent=c Instance.new("UICorner",sb).CornerRadius=UDim.new(1,0)local pct=(default-min)/(max-min)local fill=Instance.new("Frame")fill.Size=UDim2.new(pct,0,1,0)fill.BackgroundColor3=Theme.Accent fill.BorderSizePixel=0 fill.Parent=sb Instance.new("UICorner",fill).CornerRadius=UDim.new(1,0)local kn=Instance.new("Frame")kn.Size=UDim2.new(0,14,0,14)kn.Position=UDim2.new(pct,-7,0.5,-7)kn.BackgroundColor3=Color3.new(1,1,1)kn.BorderSizePixel=0 kn.Parent=sb Instance.new("UICorner",kn).CornerRadius=UDim.new(1,0)local drag=false local function upd(input)local pos=input.Position local ap=sb.AbsolutePosition local as=sb.AbsoluteSize local p=math.clamp((pos.X-ap.X)/as.X,0,1)local val=math.floor(min+(max-min)*p)fill.Size=UDim2.new(p,0,1,0)kn.Position=UDim2.new(p,-7,0.5,-7)l.Text=name..": "..val callback(val)end sb.InputBegan:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then drag=true upd(i)end end)UserInputService.InputEnded:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then drag=false end end)UserInputService.TouchMoved:Connect(function(i)if drag then upd(i)end end)end CreateToggle(AimFrame,"Aimbot",false,function(e)Settings.Aimbot=e end)CreateSlider(AimFrame,"FOV",50,500,200,function(v)Settings.AimFOV=v end)CreateSlider(AimFrame,"Suavidade",1,10,5,function(v)Settings.AimSmooth=v end)CreateToggle(VisualFrame,"ESP",true,function(e)Settings.ESP=e end)CreateToggle(VisualFrame,"Box",true,function(e)Settings.Box=e end)CreateToggle(VisualFrame,"Tracer",true,function(e)Settings.Tracer=e end)CreateToggle(VisualFrame,"Nome",true,function(e)Settings.Nome=e end)CreateToggle(VisualFrame,"Vida",true,function(e)Settings.Vida=e end)CreateToggle(MoveFrame,"Speed Hack",false,function(e)Settings.Speed=e local c=LocalPlayer.Character if c then local h=c:FindFirstChildOfClass("Humanoid")if h then if e then h.WalkSpeed=Settings.SpeedVal*Settings.Multi else h.WalkSpeed=Settings.SpeedVal end end end end)CreateSlider(MoveFrame,"Speed",1,10,3,function(v)Settings.Multi=v if Settings.Speed then local c=LocalPlayer.Character if c then local h=c:FindFirstChildOfClass("Humanoid")if h then h.WalkSpeed=Settings.SpeedVal*v end end end end)CreateToggle(MoveFrame,"Noclip",false,function(e)Settings.Noclip=e end)CreateToggle(MiscFrame,"Fullbright",false,function(e)Settings.Fullbright=e if e then Lighting.Brightness=2 Lighting.ClockTime=14 Lighting.FogEnd=100000 Lighting.GlobalShadows=false Lighting.OutdoorAmbient=Color3.fromRGB(128,128,128)Lighting.Outlines=false Lighting.Ambient=Color3.fromRGB(255,255,255)Lighting.ColorShift_Top=Color3.fromRGB(255,255,255)Lighting.ColorShift_Bottom=Color3.fromRGB(255,255,255)Lighting.EnvironmentDiffuseScale=1 Lighting.EnvironmentSpecularScale=0 else Lighting.Brightness=1 Lighting.ClockTime=14 Lighting.FogEnd=100000 Lighting.GlobalShadows=true Lighting.OutdoorAmbient=Color3.fromRGB(105,105,105)Lighting.Ambient=Color3.fromRGB(0,0,0)Lighting.ColorShift_Top=Color3.fromRGB(0,0,0)Lighting.ColorShift_Bottom=Color3.fromRGB(0,0,0)Lighting.EnvironmentDiffuseScale=1 Lighting.EnvironmentSpecularScale=1 end end)CreateToggle(MiscFrame,"God Mode",false,function(e)print("God Mode:",e and "ON"or"OFF")end)local function SwitchTab(key)TabAim.BackgroundColor3=(key=="AIM")and Theme.Accent or Color3.fromRGB(40,40,48)TabVisual.BackgroundColor3=(key=="VISUAL")and Theme.Accent or Color3.fromRGB(40,40,48)TabMove.BackgroundColor3=(key=="MOVE")and Theme.Accent or Color3.fromRGB(40,40,48)TabMisc.BackgroundColor3=(key=="MISC")and Theme.Accent or Color3.fromRGB(40,40,48)AimFrame.Visible=(key=="AIM")VisualFrame.Visible=(key=="VISUAL")MoveFrame.Visible=(key=="MOVE")MiscFrame.Visible=(key=="MISC")end TabAim.Activated:Connect(function()SwitchTab("AIM")end)TabVisual.Activated:Connect(function()SwitchTab("VISUAL")end)TabMove.Activated:Connect(function()SwitchTab("MOVE")end)TabMisc.Activated:Connect(function()SwitchTab("MISC")end)local panelOpen=false FloatButton.Activated:Connect(function()if not draggingFloat then panelOpen=not panelOpen MainPanel.Visible=panelOpen end end)CloseButton.Activated:Connect(function()panelOpen=false MainPanel.Visible=false end)local draggingFloat=false local dragStartPos=nil local startBtnPos=nil FloatButton.InputBegan:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then draggingFloat=true dragStartPos=i.Position startBtnPos=FloatButton.Position end end)UserInputService.TouchMoved:Connect(function(i)if draggingFloat then local d=i.Position-dragStartPos FloatButton.Position=UDim2.new(0,startBtnPos.X.Offset+d.X,0,startBtnPos.Y.Offset+d.Y)end end)UserInputService.InputEnded:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then draggingFloat=false end end)local draggingPanel=false local panelDragStart=nil local panelStartPos=nil TitleBar.InputBegan:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then draggingPanel=true panelDragStart=i.Position panelStartPos=MainPanel.Position end end)UserInputService.TouchMoved:Connect(function(i)if draggingPanel then local d=i.Position-panelDragStart MainPanel.Position=UDim2.new(0,panelStartPos.X.Offset+d.X,0,panelStartPos.Y.Offset+d.Y)end end)UserInputService.InputEnded:Connect(function(i)if i.UserInputType==Enum.UserInputType.Touch then draggingPanel=false end end)LocalPlayer.CharacterAdded:Connect(function(c)local h=c:WaitForChild("Humanoid",5)if h then task.wait(0.1)Settings.SpeedVal=h.WalkSpeed if Settings.Speed then h.WalkSpeed=Settings.SpeedVal*Settings.Multi end end end)local function GetClosestPlayer()local closest=nil local closestDist=Settings.AimFOV local screenCenter=Vector2.new(Camera.ViewportSize.X/2,Camera.ViewportSize.Y/2)for _,p in ipairs(Players:GetPlayers())do if p~=LocalPlayer and p.Character then local head=p.Character:FindFirstChild("Head")local hum=p.Character:FindFirstChildOfClass("Humanoid")if head and hum and hum.Health>0 then local sp,onScreen=Camera:WorldToScreenPoint(head.Position)if onScreen then local dist=(Vector2.new(sp.X,sp.Y)-screenCenter).Magnitude if dist<closestDist then closestDist=dist closest=p end end end end end return closest end RunService.RenderStepped:Connect(function()if Settings.Aimbot then local target=GetClosestPlayer()if target and target.Character then local head=target.Character:FindFirstChild("Head")if head then local cf=Camera.CFrame local targetCF=CFrame.new(cf.Position,head.Position)local smooth=1/(Settings.AimSmooth*2)Camera.CFrame=cf:Lerp(targetCF,smooth)end end end if Settings.Noclip then local char=LocalPlayer.Character if char then for _,v in ipairs(char:GetDescendants())do if v:IsA("BasePart")and v.CanCollide then v.CanCollide=false end end end end end)local ESP_Players={}local function CreateESP(player)if player==LocalPlayer then return end local c=Instance.new("Frame")c.Name=player.Name c.BackgroundTransparency=1 c.Size=UDim2.new(1,0,1,0)c.Parent=ESPGui local box=Instance.new("Frame")box.Name="Box"box.BackgroundTransparency=1 box.BorderSizePixel=2 box.BorderColor3=Color3.fromRGB(255,50,50)box.Visible=false box.Parent=c local tracer=Instance.new("Frame")tracer.Name="Tracer"tracer.BackgroundColor3=Color3.fromRGB(255,50,50)tracer.BorderSizePixel=0 tracer.Visible=false tracer.Parent=c local nl=Instance.new("TextLabel")nl.Name="Name"nl.BackgroundTransparency=1 nl.TextColor3=Color3.new(1,1,1)nl.TextStrokeTransparency=0 nl.Font=Enum.Font.SourceSansBold nl.TextSize=12 nl.TextXAlignment=Enum.TextXAlignment.Center nl.Visible=false nl.Parent=c local dl=Instance.new("TextLabel")dl.Name="Dist"dl.BackgroundTransparency=1 dl.TextColor3=Color3.fromRGB(200,200,200)dl.TextStrokeTransparency=0 dl.Font=Enum.Font.SourceSans dl.TextSize=10 dl.TextXAlignment=Enum.TextXAlignment.Center dl.Visible=false dl.Parent=c local hpBg=Instance.new("Frame")hpBg.Name="HP_BG"hpBg.BackgroundColor3=Color3.fromRGB(20,20,20)hpBg.BorderSizePixel=0 hpBg.Visible=false hpBg.Parent=c local hpBar=Instance.new("Frame")hpBar.Name="HP_Bar"hpBar.BackgroundColor3=Color3.fromRGB(0,255,0)hpBar.BorderSizePixel=0 hpBar.Parent=hpBg ESP_Players[player.Name]=c local conn conn=RunService.RenderStepped:Connect(function()pcall(function()if not player or not player.Parent then conn:Disconnect()c:Destroy()ESP_Players[player.Name]=nil return end if not Settings.ESP then c.Visible=false return end c.Visible=true local char=player.Character if not char then box.Visible=false tracer.Visible=false nl.Visible=false dl.Visible=false hpBg.Visible=false return end local root=char:FindFirstChild("HumanoidRootPart")or char:FindFirstChild("Torso")local head=char:FindFirstChild("Head")local hum=char:FindFirstChildOfClass("Humanoid")if not root or not head or not hum or hum.Health<=0 then box.Visible=false tracer.Visible=false nl.Visible=false dl.Visible=false hpBg.Visible=false return end local dist=(root.Position-Camera.CFrame.Position).Magnitude local hs,ho=Camera:WorldToScreenPoint(head.Position)local rs=Camera:WorldToScreenPoint(root.Position)local fs=Camera:WorldToScreenPoint(root.Position-Vector3.new(0,3,0))local bh=math.abs(hs.Y-fs.Y)local bw=bh*0.5 local col=Color3.fromRGB(255,50,50)if player.Team and LocalPlayer.Team and player.Team==LocalPlayer.Team then col=Color3.fromRGB(50,255,50)end if Settings.Box then box.Visible=ho box.BorderColor3=col box.Size=UDim2.new(0,bw,0,bh)box.Position=UDim2.new(0,hs.X-bw/2,0,hs.Y)else box.Visible=false end if Settings.Tracer then tracer.Visible=true tracer.BackgroundColor3=col local sx=Camera.ViewportSize.X/2 local sy=Camera.ViewportSize.Y*0.85 local ex=rs.X local ey=fs.Y local dx=ex-sx local dy=ey-sy local len=math.sqrt(dx*dx+dy*dy)tracer.Size=UDim2.new(0,len,0,2)tracer.Position=UDim2.new(0,sx,0,sy)tracer.Rotation=math.deg(math.atan2(dy,dx))else tracer.Visible=false end if Settings.Nome then nl.Visible=ho nl.Text=player.DisplayName nl.TextColor3=col nl.Size=UDim2.new(0,100,0,16)nl.Position=UDim2.new(0,hs.X-50,0,hs.Y-bh/2-18)else nl.Visible=false end dl.Visible=ho dl.Text=math.floor(dist).."m"dl.Size=UDim2.new(0,100,0,14)dl.Position=UDim2.new(0,hs.X-50,0,hs.Y+bh/2+2)if Settings.Vida then local hp=hum.Health/hum.MaxHealth hpBg.Visible=ho hpBg.Size=UDim2.new(0,3,0,bh)hpBg.Position=UDim2.new(0,hs.X-bw/2-5,0,hs.Y)hpBar.Size=UDim2.new(1,0,hp,0)hpBar.Position=UDim2.new(0,0,1-hp,0)hpBar.BackgroundColor3=Color3.fromRGB(255*(1-hp),255*hp,0)else hpBg.Visible=false end end)end)end for _,p in ipairs(Players:GetPlayers())do task.spawn(function()CreateESP(p)end)end Players.PlayerAdded:Connect(function(p)task.wait(0.3)task.spawn(function()CreateESP(p)end)end)Players.PlayerRemoving:Connect(function(p)if ESP_Players[p.Name]then ESP_Players[p.Name]:Destroy()ESP_Players[p.Name]=nil end end)
